#include <stdio.h>
#include <string.h>
#define MOD 1000000007

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        char S1[200001];
        scanf("%d %s", &N, S1);
        int M;
        char S2[200001];
        scanf("%d %s", &M, S2);
        int dp[N + 1];
        dp[0] = 0;
        for (int i = 1; i <= N; i++) {
            dp[i] = (dp[i-1] + 2) % MOD;
        }
        for (int i = M - 1; i >= 0; i--) {
            if (S2[i] != S1[N - (M - i) - 1]) {
                dp[N - (M - i)] = (dp[N - (M - i) + 1] + 2) % MOD;
            }
        }
        printf("%d\n", dp[N]);
    }
    return 0;
}

